         public ActionResult Delete(int? id)
         {
             if (id == null)
             {
                 return new StatusCodeResult((int)HttpStatusCode.BadRequest);
             }
             Student student = db.Students.Find(id);
             if (student == null)
             {
                 return NotFound();
             }
             return View(student);
         }

