using System;
using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_SetsPageIndexAndTotalPages()
        {
            var items = new List<int> { 1, 2, 3 };
            var list = new PaginatedList<int>(items, 30, 2, 10);

            Assert.Equal(2, list.PageIndex);
            Assert.Equal(3, list.TotalPages);
        }

        [Fact]
        public void Constructor_ContainsItems()
        {
            var items = new List<string> { "a", "b" };
            var list = new PaginatedList<string>(items, 5, 1, 3);

            Assert.Equal(2, list.Count);
            Assert.Equal("a", list[0]);
            Assert.Equal("b", list[1]);
        }

        [Fact]
        public void TotalPages_RoundsUp()
        {
            var list = new PaginatedList<int>(new List<int>(), 11, 1, 10);
            Assert.Equal(2, list.TotalPages);
        }

        [Fact]
        public void TotalPages_ExactDivision()
        {
            var list = new PaginatedList<int>(new List<int>(), 20, 1, 10);
            Assert.Equal(2, list.TotalPages);
        }

        [Fact]
        public void TotalPages_SinglePage()
        {
            var list = new PaginatedList<int>(new List<int>(), 5, 1, 10);
            Assert.Equal(1, list.TotalPages);
        }

        [Fact]
        public void TotalPages_ZeroItems()
        {
            var list = new PaginatedList<int>(new List<int>(), 0, 1, 10);
            Assert.Equal(0, list.TotalPages);
        }

        [Fact]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int>(), 30, 1, 10);
            Assert.False(list.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var list = new PaginatedList<int>(new List<int>(), 30, 2, 10);
            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int>(), 30, 3, 10);
            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void HasNextPage_NotLastPage_ReturnsTrue()
        {
            var list = new PaginatedList<int>(new List<int>(), 30, 1, 10);
            Assert.True(list.HasNextPage);
        }

        [Fact]
        public void HasNextPage_SinglePage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int>(), 5, 1, 10);
            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void Create_ReturnsCorrectPage()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 10);

            Assert.Equal(2, result.PageIndex);
            Assert.Equal(3, result.TotalPages);
            Assert.Equal(10, result.Count);
            Assert.Equal(11, result[0]);
            Assert.Equal(20, result[9]);
        }

        [Fact]
        public void Create_FirstPage_ReturnsCorrectItems()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(1, result.PageIndex);
            Assert.Equal(10, result.Count);
            Assert.Equal(1, result[0]);
        }

        [Fact]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var source = Enumerable.Range(1, 25).AsQueryable();

            var result = PaginatedList<int>.Create(source, 3, 10);

            Assert.Equal(3, result.PageIndex);
            Assert.Equal(5, result.Count);
            Assert.Equal(21, result[0]);
        }

        [Fact]
        public void Create_EmptySource()
        {
            var source = Enumerable.Empty<int>().AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.Equal(0, result.Count);
            Assert.Equal(0, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void Create_PageSizeOfOne()
        {
            var source = Enumerable.Range(1, 3).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 1);

            Assert.Equal(3, result.TotalPages);
            Assert.Single(result);
            Assert.Equal(2, result[0]);
        }
    }
}

